Thanks @lukepighetti, I adjusted your code a bit to center the emojis, and align the distances no matter if there's a space after the emoji or not (using trim).

```dart
class EmojiText extends StatelessWidget {
  final String text;
  final TextStyle style;
  final double emojiFontMultiplier;

  const EmojiText({
    required this.text,
    required this.style,
    this.emojiFontMultiplier = 1.4, // Increase by 40%
  });

  // Regex to match emojis
  static final regex = RegExp("(\u00a9|\u00ae|[\u2000-\u3300]|\ud83c[\ud000-\udfff]|\ud83d[\ud000-\udfff]|\ud83e[\ud000-\udfff])");

  List<InlineSpan> generateTextSpans(String text) {
    List<InlineSpan> spans = [];
    final TextStyle emojiStyle = style.copyWith(
      fontSize: (style.fontSize! * emojiFontMultiplier),
      letterSpacing: 2,
      height: 1.1,
    );

    text.splitMapJoin(
      regex,
      onMatch: (m) {
        spans.add(
          WidgetSpan(
            alignment: PlaceholderAlignment.middle,
            child: Text(m.group(0) ?? '', style: emojiStyle),
          ),
        );
        return "";
      },
      onNonMatch: (s) {
        spans.add(TextSpan(text: s.trim()));
        return "";
      },
    );
    return spans;
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      child: RichText(
        strutStyle: StrutStyle(
          forceStrutHeight: true,
        ),
        text: TextSpan(
          children: generateTextSpans(text),
          style: style,
        ),
      ),
    );
  }
}
```

Usage:

```dart
EmojiText(
  text: 'Hello world 😊',
  style: TextStyle(
    fontSize: 15,
  ),
)
```

![image](https://user-images.githubusercontent.com/3786627/201613799-d55cc6d0-823f-46ea-a7e9-99ab76ad161d.png)

I've spent the last day or so looking at this. Here's what I can tell:

- Skia is doing exactly what we ask it to - rendering an emoji from Apple Color Emoji at the exact font size we're asking for.
- A simple program using CoreText shows the same behavior.
- A simple program purely using Skia shows the same behavior.
- On macOS, a SwiftUI "Text" widget shows the same behavior.
- Safari and Chrome show the same behavior on macOS.

iOS seems to have some kind of special handling in Safari/Chrome/UIKit/SwiftUI, where AppleColorEmoji are scaled up a bit from what their normal size would be. I initially thought this was a multiplier of something like 125% (which is about what the scaling difference is when the font size is 16), but at larger sizes it goes away. I tried a test of rendering emoji at increasing sizes and the increase seems to be nearly linear for a 🤔 emoji:

|Font Size|Glyph Height|
|---|---|
|11 | 28 |
|12 | 30|
|13 | 32|
|14 | 34|
|15 | 38|
|16 | 40|
|17 | 40|
|18 | 40|
|19 | 41|
|20 | 42|
|21 | 43|
|22 | 44|
|23 | 46|
|24 | 48|
|25 | 50|
|26 | 52|
|27 | 54|
|28 | 56|
|29 | 56|
|30 | 58|

You can see this in https://github.com/indjec/ui-label if you change the font size to something sufficiently large - there are still some spacing differences but the size difference is much less noticeable at larger font sizes.

I'm not quite sure what to do about this. One option would be to have some mode in Skia that lets us bump up the size a bit when the font is Apple Color Emoji and use that only on iOS. That's probably good enough to improve the fidelity. It's a bit disappointing that UIKit isn't open source to be able to see what it's doing with this or why it renders things any differently here. I tried finding relevant code in WebKit and couldn't.

Some sample programs:

A basic CoreText program that renders some Apple Color Emoji more-or-less the way Skia does to a png:

```objc
#include <Foundation/foundation.h>

#include <CoreFoundation/CoreFoundation.h>
#include <CoreGraphics/CoreGraphics.h>
#include <CoreText/CTFontManager.h>
#include <CoreText/CoreText.h>
#include <ImageIO/ImageIO.h>
#include <UniformTypeIdentifiers/UniformTypeIdentifiers.h>

int main() {
  CTFontRef ct_font = CTFontCreateWithName((CFStringRef) @"Apple Color Emoji",
                                           (CGFloat)30, nullptr);

  if (!ct_font) {
    printf("Canot find Apple Color Emoji?\n");
    return -1;
  }

  CGGlyph glyphs[2];
  glyphs[0] = 1089;
  glyphs[1] = 2427;
  CGPoint positions[2];
  positions[0] = CGPointMake(50, 50);
  positions[1] = CGPointMake(90, 50);

  const CGBitmapInfo bitmapInfo =
      kCGBitmapByteOrder32Host | kCGImageAlphaPremultipliedFirst;

  size_t width = 200;
  size_t height = 100;
  size_t row_bytes = width * sizeof(uint32_t);

  unsigned short image[height * row_bytes];

  CGContextRef context =
      CGBitmapContextCreate(image, width, height, 8, row_bytes,
                            CGColorSpaceCreateDeviceRGB(), bitmapInfo);

  CTFontDrawGlyphs(ct_font, glyphs, positions, 2, context);

  CGContextFlush(context);

  CGImageRef out_image = CGBitmapContextCreateImage(context);
  CFURLRef url =
      (__bridge CFURLRef)[[NSURL alloc] initFileURLWithPath:@"emoji.png"];
  CGImageDestinationRef destination = CGImageDestinationCreateWithURL(
      url, (__bridge CFStringRef)UTTypePNG.identifier, 1, nil);
  CGImageDestinationAddImage(destination, out_image, nil);
  CGImageDestinationFinalize(destination);
  CFRelease(destination);

  return 0;
}
```

A Skia test (only really makes sense on iOS/macOS):

```cpp
    auto manager = SkFontMgr::RefDefault();
    auto aceType = manager->matchFamilyStyle("Apple Color Emoji", SkFontStyle());
    auto arialType = manager->matchFamilyStyle("Arial", SkFontStyle());

    auto fontSizes = {12, 16, 24, 30, 32, 64, 128};
    SkScalar y = 100;
    for (auto fontSize : fontSizes) {
        SkTextBlobBuilder textBlobBuilder;
        SkTextBlobBuilder textBlobBuilder2;
        SkFont aceFont(aceType, fontSize);
        SkFont arialFont(arialType, fontSize);

        const SkTextBlobBuilder::RunBuffer& run1 = textBlobBuilder.allocRun(arialFont, 4, 10, y);
        run1.glyphs[0] = 39;
        run1.glyphs[1] = 72;
        run1.glyphs[2] = 80;
        run1.glyphs[3] = 82;

        SkRect bounds[4];
        arialFont.getBounds(run1.glyphs, 4, bounds, nullptr);
        SkScalar advance = 0;
        for (size_t i = 0; i < 4; i++) {
            advance += bounds[i].width();
        }
        const SkTextBlobBuilder::RunBuffer& run2 =
                textBlobBuilder2.allocRun(aceFont, 2, advance + fontSize / 2, y);
        run2.glyphs[0] = 1089;
        run2.glyphs[1] = 2427;
        sk_sp<const SkTextBlob> blob = textBlobBuilder.make();
        sk_sp<const SkTextBlob> blob2 = textBlobBuilder2.make();

        SkPaint paint;
        paint.setColor(SK_ColorBLUE);
        canvas->drawTextBlob(blob.get(), 0, 0, paint);
        canvas->drawTextBlob(blob2.get(), 0, 0, paint);
        y += aceFont.getMetrics(nullptr) * 2;
    }
```

